// 1. Preparamos el entorno para procesar TODOS los registros de un golpe
const items = $input.all();
const urlCache = new Map(); // Aquí evitamos los pings repetidos
const results = [];

// Función para elegir mensaje aleatorio (La esencia)
const pick = (arr) => arr[Math.floor(Math.random() * arr.length)];

for (const item of items) {
  const data = item.json;
  const url = data.url;
  const method = data.method || 'GET';
  const name = data.name;
  const avg = parseFloat(data.avg_latency) || 0;

  let pingResult;

  // --- CAPA DE EFICIENCIA (1 PING POR URL) ---
  if (urlCache.has(url)) {
    pingResult = urlCache.get(url);
  } else {
    const start = Date.now();
    try {
      const response = await this.helpers.httpRequest({
        method: method,
        url: url,
        timeout: 5000,
        headers: { 'User-Agent': 'Diagnosta-SRE-Bot-v5', 'Accept': '*/*' },
        returnFullResponse: true
      });
      const end = Date.now();
      pingResult = {
        ms: end - start,
        code: response.statusCode || 200,
        success: (response.statusCode || 200) < 400,
        error: null
      };
    } catch (e) {
      const end = Date.now();
      pingResult = {
        ms: end - start,
        code: e.response?.statusCode || 500,
        success: false,
        error: e.message
      };
    }
    urlCache.set(url, pingResult); // Guardamos resultado técnico para otros usuarios
  }

  // --- CAPA DE INTELIGENCIA (ESPECÍFICA POR USUARIO) ---
  const ms = pingResult.ms;
  const code = pingResult.code;
  const diff = avg > 0 ? Math.round(((ms - avg) / avg) * 100) : 0;

  // Templates inyectados dentro del bucle para asegurar originalidad por cada fila
  const fName = `(   ${name.toUpperCase()}   )`;
  const templates = {
    RED_BUENA: [
      `Telemetría de ${fName}: Latencia ultra-baja (${ms}ms). Enlace optimizado.`,
      `Capa de transporte estable. RTT hacia ${fName} es de ${ms}ms.`,
      `Flujo de paquetes óptimo. Tráfico hacia ${fName} sin congestión: ${ms}ms.`,
      `Rendimiento pico en ${fName}. Tiempo de respuesta de red: ${ms}ms.`,
      `Conectividad sólida. ${fName} completó sincronización en ${ms}ms.`,
      `Traza de red nominal hacia ${fName}. Latencia registrada: ${ms}ms.`,
      `Infraestructura de red estable detectada para ${fName}.`
    ],
    RED_MALA: [
      `Degradación en la red de ${fName}. Latencia: ${ms}ms (Desviación: ${diff}%).`,
      `Congestión detectada en la ruta hacia ${fName}. Alerta: ${ms}ms.`,
      `Inestabilidad en el transporte de ${fName}. Respuesta lenta detectada: ${ms}ms.`,
      `Jitter inusual en ${fName}. La latencia escaló a ${ms}ms.`,
      `Presión en el tráfico. ${fName} reporta tiempo degradado: ${ms}ms.`
    ],
    PROT_OK: [
      `Handshake exitoso en ${fName}. Protocolo validado (Code ${code}).`,
      `Negociación TLS en ${fName} completada. Servidor responde íntegro (${code}).`,
      `Capa de aplicación de ${fName} nominal. Status ${code} verificado.`,
      `Cabeceras de ${fName} íntegras. Negociación HTTP finalizada (${code}).`,
      `Sesión con ${fName} establecida. El protocolo reporta salud (Code ${code}).`,
      `Intercambio validado. ${fName} devuelve cabeceras estándar (${code}).`,
      `Handshake TCP/HTTP 1.1 verificado para ${fName}. Status ${code}.`
    ],
    PROT_ERROR: [
      `Anomalía lógica en ${fName}. El protocolo devolvió error: ${code}.`,
      `Fallo en la negociación de capa 7 para ${fName}. Status ${code} detectado.`,
      `Integridad de ${fName} comprometida. Respuesta inusual: ${code}.`,
      `Error de protocolo en ${fName}. Se requiere revisión del Status ${code}.`,
      `Handshake rechazado. El nodo ${fName} reporta estado crítico ${code}.`
    ]
  };

  const redStatus = (ms > 800 || diff > 40) ? 'RED_MALA' : 'RED_BUENA';
  const protStatus = (code >= 400) ? 'PROT_ERROR' : 'PROT_OK';

  const insights = [
    { cat: 'RED',  msg: pick(templates[redStatus]) },
    { cat: 'PROT', msg: pick(templates[protStatus]) }
  ];

  results.push({
    json: {
      endpoint_id: data.id, // Para el nodo Guardar en DB
      user_id: data.user_id,
      name: name,
      status_code: code,
      latency_ms: ms,
      is_success: pingResult.success,
      checked_at: new Date().toISOString(),
      quick_insights: JSON.stringify(insights),
      error_type: pingResult.error,
      response_preview: pingResult.success ? "OK" : pingResult.error
    }
  });
}

return results;

// 1. Limpieza de procesos para medición de latencia pura
await new Promise(resolve => setImmediate(resolve));

const url = $json.url;
const method = $json.method || 'GET';
const start = Date.now();

try {
  const response = await this.helpers.httpRequest({
    method: method,
    url: url,
    timeout: 5000,
    headers: { 'User-Agent': 'Diagnosta-SRE-Bot' },
    returnFullResponse: true  
  });

  const end = Date.now();
  const b = response.body;

  // Lógica de Producción: Diferenciamos entre JSON real y falta de contenido
  const preview = (!b || b === '' || Object.keys(b).length === 0)
    ? null
    : (typeof b === 'string' ? b.substring(0, 500) : JSON.stringify(b).substring(0, 500));

  return {
    endpoint_id: $json.id,
    status_code: response.statusCode || 200,
    latency_ms: end - start,
    is_success: (response.statusCode || 200) < 400,
    error_type: null,
    response_preview: preview, // Enviamos NULL si no hay payload útil
    checked_at: new Date().toISOString()
  };
} catch (error) {
  const end = Date.now();
  return {
    endpoint_id: $json.id,
    status_code: error.response?.statusCode || 500,
    latency_ms: end - start,
    is_success: false,
    error_type: 'http_error',
    response_preview: error.message,
    checked_at: new Date().toISOString()
  };
}
